import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../store/hooks';
import { MONTH_OPTIONS, yearOptions } from '../constants/voucher';
import { wmsService } from '../services/kho/wmsService';
import type {
  DevSampleDataResultDto,
  DevSampleDataVoucherDto,
  DevSampleDataReportLineDto,
} from '../services/kho/models';
import { getApiErrorMessage } from '../utils/getApiErrorMessage';
import { KHO_PATHS, MH_PATHS } from '../appPaths';
import df from '../styles/documentForm.module.css';
import erp from '../styles/erpPage.module.css';

const SMOKE_LINKS = [
  { label: 'Phiếu nhập kho', url: KHO_PATHS.pnk },
  { label: 'Phiếu xuất kho', url: KHO_PATHS.pxk },
  { label: 'Tồn kho', url: KHO_PATHS.tonKho },
  { label: 'Thẻ kho', url: KHO_PATHS.theKho },
  { label: 'Yêu cầu mua hàng', url: MH_PATHS.ycmh },
  { label: 'Đơn đặt hàng', url: MH_PATHS.ddmh },
  { label: 'Phiếu nhận hàng', url: MH_PATHS.nhanHang },
  { label: 'BC kho công đoạn', url: KHO_PATHS.baoCaoKhoCongDoan },
  { label: 'BC thành phẩm lỗi', url: KHO_PATHS.baoCaoThanhPhamLoi },
] as const;

const DevSampleDataPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [running, setRunning] = useState(false);
  const [result, setResult] = useState<DevSampleDataResultDto | null>(null);

  const handleGenerate = async () => {
    setRunning(true);
    try {
      const data = await wmsService.generateDevSampleData(Number(month), Number(year));
      setResult(data);
      dispatch(addToast({ message: data.message, type: 'success' }));
    } catch (e: unknown) {
      dispatch(addToast({
        message: getApiErrorMessage(e, 'Tạo dữ liệu mẫu thất bại'),
        type: 'error',
      }));
    } finally {
      setRunning(false);
    }
  };

  return (
    <div className={df.page} data-testid="dev-sample-data-page">
      <div className={df.stickyTop}>
        <div className={df.pageHeader}>
          <div className={df.titleGroup}>
            <h1 className={df.title} data-testid="dev-sample-data-title">
              <i className="fas fa-database" style={{ marginRight: 8 }} />
              Tạo dữ liệu mẫu Supply
            </h1>
            <p style={{ margin: '4px 0 0', fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}>
              Dev only — PNK/PXK + YCMH/ĐĐMH/PNH để smoke list/form và báo cáo kho.
            </p>
          </div>
        </div>
      </div>

      <div className={df.section}>
        <h2 className={df.sectionTitle}>Kỳ dữ liệu</h2>
        <p style={{ margin: '0 0 12px', fontSize: 13, lineHeight: 1.5 }}>
          Tạo 2× PNK, 2× PXK (Posted), 1× YCMH (Approved), 1× PO (Confirmed), 1× PNH (Posted).
          Số tiền mỗi dòng <strong>random bội 1.000 VND</strong>. Mô tả <code>[DEMO]</code>.
          Cần GL/báo cáo KT: chạy thêm Finance <code>/kt/dev/tao-du-lieu-mau</code>.
        </p>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Tháng</label>
            <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Năm</label>
            <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
          </div>
          <div className={df.field} aria-hidden />
          <div className={df.field} aria-hidden />
        </div>
        <div style={{ marginTop: 12 }}>
          <Button
            variant="primary"
            data-testid="dev-sample-data-generate-btn"
            onClick={handleGenerate}
            loading={running}
          >
            Tạo dữ liệu mẫu
          </Button>
        </div>
      </div>

      {result && (
        <div className={df.section} data-testid="dev-sample-data-result">
          <h2 className={df.sectionTitle}>Kết quả — kỳ {result.month}/{result.year}</h2>
          <p style={{ margin: '0 0 12px', fontSize: 13 }}>{result.message}</p>
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th>Loại</th>
                  <th>Mã</th>
                  <th>Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {result.vouchers.map((v: DevSampleDataVoucherDto) => (
                  <tr key={v.id}>
                    <td>{v.documentType}</td>
                    <td><code>{v.code}</code></td>
                    <td>{v.status}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          {result.reports?.length > 0 && (
            <>
              <h3 className={df.sectionTitle} style={{ marginTop: 16 }}>Báo cáo / danh sách kiểm tra</h3>
              <div className={erp.tableWrapper}>
                <table className={erp.table}>
                  <thead>
                    <tr>
                      <th>Báo cáo</th>
                      <th>Route FE</th>
                      <th>API (tham chiếu)</th>
                    </tr>
                  </thead>
                  <tbody>
                    {result.reports.map((r: DevSampleDataReportLineDto) => (
                      <tr key={r.reportCode}>
                        <td><Link to={r.feRoute}>{r.reportName}</Link></td>
                        <td><code>{r.feRoute}</code></td>
                        <td style={{ fontSize: 12 }}><code>{r.apiPath}</code></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </>
          )}
        </div>
      )}

      <div className={df.section}>
        <h2 className={df.sectionTitle}>Mở trang kiểm tra</h2>
        <ul style={{ margin: 0, paddingLeft: 20, fontSize: 13, lineHeight: 1.8 }}>
          {SMOKE_LINKS.map(r => (
            <li key={r.url}>
              <Link to={r.url}>{r.label}</Link>
            </li>
          ))}
        </ul>
        <p style={{ margin: '12px 0 0', fontSize: 12, color: 'var(--color-text-secondary, #6c757d)' }}>
          API: <code>POST /wms/dev/sample-data?month=&amp;year=</code> · chỉ Development/Docker (DevAuth).
        </p>
      </div>
    </div>
  );
};

export default DevSampleDataPage;
